class Semaphore {
  constructor(max) { this.max = max; this.count = 0; this.queue = []; }
  async acquire(timeoutMs = 100) {
    if (this.count < this.max) { this.count++; return; }
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => { this.queue = this.queue.filter(q => q !== resolver); reject(new Error('bulkhead: timeout')); }, timeoutMs);
      const resolver = () => { clearTimeout(timer); resolve(); };
      this.queue.push(resolver);
    }).then(() => { this.count++; });
  }
  release() { this.count--; if (this.queue.length) { const next = this.queue.shift(); next(); } }
}

const paymentsBulkhead = new Semaphore(5);
async function safeCall(fn, bulkhead) {
  try { await bulkhead.acquire(200); } catch (e) { throw new Error('Service busy'); }
  try { return await fn(); } finally { bulkhead.release(); }
}
